const ProfilePostCards = () =>{
    const queryClient = useQueryClient();
    const {user, session}= useAuth();
    const navigate = useNavigate();

    const [showEditor, setShowEditor] = useState(null);

    const {ref, inView} = useInView({
        threshold: 0.2
    })

    const settingsList = [
        {
            label: 'Delete journal',
