 388→            reason: 'invalid_or_non_http_url',
 389→            resolvedUrl: null,
 390→        };
 391→    }
 392→
 393→    let path = '';
 394→    try {
 395→        const parsed = new URL(absoluteUrl);
 396→        path = String(parsed.pathname || '').toLowerCase();
 397→    } catch {
 398→        return {
 399→            ok: false,
 400→            reason: 'invalid_resolved_url',
 401→            resolvedUrl: null,
