 413→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
 414→        return {
 415→            ok: false,
 416→            reason: 'unsafe_remote_url',
 417→            resolvedUrl: absoluteUrl,
 418→        };
 419→    }
 420→
 421→    return {
 422→        ok: true,
 423→        reason: 'ok',
 424→        resolvedUrl: absoluteUrl,
 425→    };
 426→};
