    color: var(--bg-primary);
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    cursor: pointer;
    transition:
        transform 0.15s ease,
        box-shadow 0.2s ease,
        background-color 0.2s ease;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.primary-button:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.primary-button:active:not(:disabled) {
    transform: translateY(0);
}

.primary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
}

.button-label {
    display: inline-block;
}

.button-spinner {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: #fff;
    animation: spin 0.7s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

.secondary-button {
    width: 100%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 13px 18px;
    border-radius: 8px;
    border: 1px solid var(--border-card);
    background: transparent;
    color: var(--text-secondary);
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 500;
    cursor: pointer;
    transition:
        border-color 0.2s ease,
        background-color 0.2s ease,
        color 0.2s ease;
}

.secondary-button:hover:not(:disabled) {
    border-color: var(--accent-amber);
    background: rgba(212, 168, 83, 0.04);
    color: var(--accent-amber);
}

.secondary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── Captcha ── */
.captcha-container {
    display: flex;
    justify-content: center;
    padding: 4px 0;
}

/* ── Footer Link ── */
.auth-footer {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding-top: 8px;
    border-top: 1px solid var(--border-card);
    color: var(--text-muted);
    font-size: 0.85rem;
}

.link-button {
    background: none;
    border: none;
    color: var(--accent-amber);
    font-family: var(--font-ui);
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    padding: 0;
    transition: color 0.15s ease;
}

.link-button:hover {
    color: var(--text-heading);
    text-decoration: underline;
    text-underline-offset: 3px;
}

.link-button:focus-visible {
    outline: 2px solid var(--accent-amber);
    outline-offset: 2px;
    border-radius: 4px;
}

/* ── Messages ── */
.form-message {
    padding: 12px 14px;
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 500;
    border: 1px solid transparent;
    animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

.form-message.error {
    background: var(--color-danger-bg);
    color: var(--color-danger);
    border-color: rgba(220, 38, 38, 0.2);
}

.form-message.success {
    background: var(--color-success-bg);
    color: var(--color-success);
    border-color: rgba(22, 163, 74, 0.2);
}

/* ══════════════════════════════════════════════════════════════════════════
   RESPONSIVE BREAKPOINTS
   ══════════════════════════════════════════════════════════════════════════ */

@media (prefers-reduced-motion: reduce) {
    .auth-form-card {
        animation: none;
    }
    .auth-panel::before,
    .auth-panel::after {
        animation: none;
    }
    .primary-button,
    .secondary-button,
    .auth-input,
    .show-toggle {
        transition: none;
    }
}

@media (max-width: 1024px) {
    .auth-shell {
        display: flex;
        flex-direction: column;
        min-height: 100svh;
        height: auto;
    }

    .auth-panel {
        flex-shrink: 0;
        padding: 48px 40px;
        border-right: none;
        border-bottom: 1px solid var(--border-card);
    }

    .panel-title {
        font-size: 2rem;
        max-width: 100%;
    }

    .panel-copy {
        max-width: 100%;
    }

    .auth-form-panel {
        flex: 1;
        padding: 40px 24px 56px;
    }

    .auth-form-card {
        max-width: 100%;
        box-shadow: none;
        background: transparent;
        border: none;
        padding: 0;
    }
}

@media (max-width: 600px) {
    .auth-shell {
        min-height: auto;
    }

    .auth-panel {
        padding: 36px 24px;
    }

    .brand {
        font-size: 0.9rem;
        margin-bottom: 32px;
    }

    .panel-title {
        font-size: 1.65rem;
        line-height: 1.3;
    }

    .panel-copy {
        font-size: 1rem;
        margin-bottom: 24px;
    }

    .panel-details {
        font-size: 0.65rem;
        flex-wrap: wrap;
        gap: 12px;
    }

    .auth-form-panel {
        padding: 32px 20px 48px;
    }

    .form-title {
        font-size: 1.35rem;
    }

    .form-subtitle {
        font-size: 0.9rem;
    }

    .auth-input {
        padding: 12px 14px;
        font-size: 16px; /* Prevents iOS zoom */
    }

    .primary-button,
    .secondary-button {
        padding: 12px 16px;
    }
}

/* ══════════════════════════════════════════════════════════════════════════
   DARK MODE ENHANCEMENTS
   ══════════════════════════════════════════════════════════════════════════ */

[data-theme="dark"] .auth-panel::before {
    background: radial-gradient(
        ellipse at 30% 30%,
        rgba(212, 168, 83, 0.06),
        transparent 70%
    );
}

[data-theme="dark"] .auth-panel::after {
    background: radial-gradient(
        ellipse at 70% 60%,
        rgba(212, 168, 83, 0.04),
        transparent 70%
    );
}

[data-theme="dark"] .brand::after {
    opacity: 0.3;
}

[data-theme="dark"] .panel-title,
[data-theme="dark"] .form-title {
    color: var(--text-heading);
}

[data-theme="dark"] .panel-copy,
[data-theme="dark"] .form-subtitle {
    color: var(--text-body);
}

[data-theme="dark"] .panel-details {
    color: var(--text-muted);
}

[data-theme="dark"] .auth-form-card {
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.2);
}

[data-theme="dark"] .auth-input {
    background: var(--bg-elevated);
    color: var(--text-primary);
    border-color: var(--border-light);
}

[data-theme="dark"] .auth-input::placeholder {
    color: var(--text-muted);
}

[data-theme="dark"] .auth-input:focus {
    background: var(--bg-elevated);
}

[data-theme="dark"] .length-counter {
    color: var(--text-muted);
}

[data-theme="dark"] .primary-button {
    background: var(--accent-amber);
    color: #1A1612;
}

[data-theme="dark"] .primary-button:hover:not(:disabled) {
    box-shadow: 0 4px 20px rgba(212, 168, 83, 0.25);
}

